refsection.programlisting:
image1 = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
image1 = imresize(image1, [120 160]);
image2 = imread(fullpath(getIPCVpath() + "/images/opencv_fruits.jpg"));
image2 = imresize(image2, [120 160]);
image3 = imread(fullpath(getIPCVpath() + "/images/opencv_left01.jpg"));
image3 = imresize(image3, [120 160]);
image4 = imread(fullpath(getIPCVpath() + "/images/opencv_left02.jpg"));
image4 = imresize(image4, [120 160]);
images = list(image1, image2, image3, image4);
mosaic = imtile(images, [2 2]);
imshow(mosaic);
